package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.criteria.Criterium;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.jpa.gl.ConstantPK;
import be.schaubroeck.lpb.tools.jpa.gl.ConstantPO;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.util.AdminAdvice;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import be.schaubroeck.temporal.util.TemporalContext;
import lombok.Data;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.Arrays;
import java.util.Collection;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

public class CachedConstantService implements CachedService, ConstantService {

    @Autowired
    private ConstantService constantService;

    private static final ThreadLocal<CachedConstantBuffer> BUFFER = new ThreadLocal<>();

    private static final LocalDateTime RECORD_TIME_PATCH_HASTA = new LocalDateTime(2003, 6, 5, 9, 27);
    private static final LocalDate LOOKUP_DATE_PATCH_HASTA = new LocalDate(2002, 11, 30);

    private static final LocalDateTime RECORD_TIME_PATCH_WERKBONUS_2011 = new LocalDateTime(2011, 9, 10, 0, 0);
    private static final LocalDate LOOKUP_DATE_PATCH_WERKBONUS_2011 = new LocalDate(2011, 5, 31);

    private static final LocalDateTime RECORD_TIME_PATCH_EINDE_FISCAAL_JAAR_2009_2010 = new LocalDateTime(2010, 11, 4, 0, 0);
    private static final LocalDate PATCH_DATE_EINDE_FISCAAL_JAAR_2009_2010 = new LocalDate(2010, 1, 9);

    private static final LocalDateTime RECORD_TIME_PATCH_FUNCTIECOMPLEMENT = new LocalDateTime(2011, 1, 26, 0, 0);
    private static final LocalDate LOOKUP_DATE_PATCH_FUNCTIECOMPLEMENT = new LocalDate(2010, 9, 30);

    public CachedConstantService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }

    @Override
    public void clearCache() {
        CachedConstantService.getBuffer().clear();
    }

    @Override
    public Constant getByCodeDatum(Admin admin, Integer code, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedConstantService.getByCodeDatum");
        ConstantKey key = new ConstantKey(code);
        Constant result = null;
        CachedConstantBuffer buffer = CachedConstantService.getBuffer();
        List<Constant> loLijst = buffer.getLoLijst(key);
        List<Constant> glLijst = buffer.getGlLijst(key);

        if (loLijst == null) {
            loLijst = getLOByCodeCache(admin, code);
            buffer.putLoLijst(key, loLijst);
        }

        if (glLijst == null) {
            glLijst = getGLByCodeCache(code);
            buffer.putGlLijst(key, glLijst);
        }

        if (admin != AdminAdvice.ADMIN_IGNORE) {
            result = zoekLijst(loLijst, datum);
        }
        if (result == null) {
            //            recordtime patch zie alterS191
            if ((code == 4210003 || code == 4210004) && datum.isAfter(LOOKUP_DATE_PATCH_HASTA) && TemporalContext.getInstance().getWerkTijdstip()
                    .isBefore(RECORD_TIME_PATCH_HASTA)) {

                datum = LOOKUP_DATE_PATCH_HASTA;

            } else if ((code.equals(Konstanten.KST_LL_A.getCode()) || code.equals(Konstanten.KST_LL_A1.getCode())) && datum
                    .isAfter(LOOKUP_DATE_PATCH_WERKBONUS_2011) && TemporalContext.getInstance().getWerkTijdstip()
                    .isBefore(RECORD_TIME_PATCH_WERKBONUS_2011)) {
                datum = LOOKUP_DATE_PATCH_WERKBONUS_2011;
            } else if (code == 8340030 && datum.isAfter(LOOKUP_DATE_PATCH_FUNCTIECOMPLEMENT) && TemporalContext.getInstance().getWerkTijdstip()
                    .isBefore(RECORD_TIME_PATCH_FUNCTIECOMPLEMENT)) {
                datum = LOOKUP_DATE_PATCH_FUNCTIECOMPLEMENT;
            }

            result = zoekLijst(glLijst, datum);

            if (code.equals(Konstanten.KST_FISKAAL_JAAR.getCode()) && datum.getYear() == 2009 && TemporalContext.getInstance().getWerkTijdstip()
                    .isBefore(RECORD_TIME_PATCH_EINDE_FISCAAL_JAAR_2009_2010)) {
                result = new ConstantPO((ConstantPO) result);
                result.setDatum(PATCH_DATE_EINDE_FISCAAL_JAAR_2009_2010);
            }
        }
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }

    private Constant zoekLijst(List<Constant> lijst, LocalDate datum) {
        Constant result = null;
        for (Constant constant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(constant.getBeginDatum(), constant.getEindDatum());
            if (periode.contains(datum)) {
                result = constant;
                break;
            }
        }
        return result;
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    private List<Constant> getLOByCodeCache(Admin admin, Integer constanteCode) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("id.constanteCode", Criterium.EQ(constanteCode));
        return constantService.findByCriteria(admin, cb);
    }

    private List<Constant> getGLByCodeCache(Integer constanteCode) {
        CriteriaBuilder cb = new CriteriaBuilder();
        cb.and("id.constanteCode", Criterium.EQ(constanteCode));
        return constantService.findByCriteria(cb);
    }

    private static class CachedConstantBuffer {

        private final Map<ConstantKey, List<Constant>> constantLoBuffer = new HashMap<>();
        private final Map<ConstantKey, List<Constant>> constantGlBuffer = new HashMap<>();

        public List<Constant> getLoLijst(ConstantKey key) {
            return constantLoBuffer.get(key);
        }

        public List<Constant> getGlLijst(ConstantKey key) {
            return constantGlBuffer.get(key);
        }

        public void putLoLijst(ConstantKey key, List<Constant> loLijst) {
            constantLoBuffer.put(key, loLijst);
        }

        public void putGlLijst(ConstantKey key, List<Constant> glLijst) {
            constantGlBuffer.put(key, glLijst);
        }

        public void clear() {
            constantLoBuffer.clear();
            constantGlBuffer.clear();
        }
    }

    private static CachedConstantBuffer getBuffer() {
        CachedConstantBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedConstantBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class ConstantKey {

        private final int kode;
    }

    //Forwarding naar StandardConstantService, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public Constant getByCodeDatum(Admin admin, Konstanten constant, LocalDate datum) {
        return getByCodeDatum(admin, constant.getCode(), datum);
    }

    @Override
    public List<Constant> getAllGL(Integer code) {
        return constantService.getAllGL(code);
    }


    @Override
    public Constant getActual(Admin admin, Konstanten code) {
        return getActual(admin, code.getCode());
    }

    @Override
    public Constant getActual(Admin admin, Integer code) {
        LocalDateInterval actualInterval = TemporalContext.getInstance().getActualInterval();
        return getByCodeDatum(admin, code, actualInterval.getEnd());
    }

    @Override
    public String getConstanteWaarde(Admin admin, Integer code) {
        return constantService.getConstanteWaarde(admin, code);
    }

    @Override
    public Map<LocalDateInterval, Constant> findByCode(Admin admin, Integer code) {
        return constantService.findByCode(admin, code);
    }

    @Override
    public Map<LocalDateInterval, Constant> findLOByCode(Admin admin, Integer code) {
        return constantService.findLOByCode(admin, code);
    }

    @Override
    public Map<LocalDateInterval, Constant> findGLByCode(Integer code) {
        return constantService.findGLByCode(code);
    }

    @Override
    public Collection<Constant> getGlobalByCodes(Integer... codes) {
        return Arrays.stream(codes)
                .map(this::getGlobalConstants)
                .flatMap(Collection::stream)
                .collect(Collectors.toList());
    }

    @Override
    public Collection<Constant> getLocalByCodes(Admin admin, Integer... codes) {
        return Arrays.stream(codes)
                .map(c -> getLocalConstants(admin, c))
                .flatMap(Collection::stream)
                .collect(Collectors.toList());
    }

    @Override
    public Constant getById(Integer id) {
        return constantService.getById(id);
    }

    @Override
    public Constant getById(Integer id, String fetchFields) {
        return constantService.getById(id, fetchFields);
    }

    @Override
    public Constant getByCriteria(CriteriaBuilder cb) {
        return constantService.getByCriteria(cb);
    }

    @Override
    public List<Constant> findAll() {
        return constantService.findAll();
    }

    @Override
    public List<Constant> findAll(String fetchFields) {
        return constantService.findAll(fetchFields);
    }

    @Override
    public List<Constant> findByCriteria(CriteriaBuilder cb) {
        return constantService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return constantService.countByCriteria(cb);
    }

    @Override
    public Constant create(Admin admin, Constant constant) {
        return constantService.create(admin, constant);
    }

    @Override
    public Constant update(Admin admin, Constant constant) {
        return constantService.update(admin, constant);
    }

    @Override
    public void delete(Admin admin, Constant constant) {
        constantService.delete(admin, constant);
    }

    @Override
    public Constant getById(Admin admin, ConstantPK id) {
        return constantService.getById(admin, id);
    }

    @Override
    public Constant getById(Admin admin, ConstantPK id, String fetchFields) {
        return constantService.getById(admin, id, fetchFields);
    }

    @Override
    public Constant getByCriteria(Admin admin, CriteriaBuilder cb) {
        return constantService.getByCriteria(admin, cb);
    }

    @Override
    public List<Constant> findAll(Admin admin) {
        return constantService.findAll(admin);
    }

    @Override
    public List<Constant> findAll(Admin admin, String fetchFields) {
        return constantService.findAll(admin, fetchFields);
    }

    @Override
    public List<Constant> findByCriteria(Admin admin, CriteriaBuilder cb) {
        return constantService.findByCriteria(admin, cb);
    }

    @Override
    public Integer countByCriteria(Admin admin, CriteriaBuilder cb) {
        return constantService.countByCriteria(admin, cb);
    }

    private List<Constant> getGlobalConstants(Integer code) {
        ConstantKey key = new ConstantKey(code);
        CachedConstantBuffer buffer = CachedConstantService.getBuffer();
        List<Constant> constants = buffer.getGlLijst(key);
        if (constants == null) {
            constants = getGLByCodeCache(code);
            buffer.putGlLijst(key, constants);
        }
        return constants;
    }

    private List<Constant> getLocalConstants(Admin admin, Integer code) {
        ConstantKey key = new ConstantKey(code);
        CachedConstantBuffer buffer = CachedConstantService.getBuffer();
        List<Constant> constants = buffer.getLoLijst(key);
        if (constants == null) {
            constants = getLOByCodeCache(admin, code);
            buffer.putLoLijst(key, constants);
        }
        return constants;
    }
}
